  'Fullstack':    { 'Under 1 year':{median:12,p25:9,p75:15},  '1–2 yrs':{median:17,p25:13,p75:23}, '3–4 yrs':{median:27,p25:21,p75:34}, '5–7 yrs':{median:38,p25:30,p75:48}, '8+ yrs':{median:52,p25:42,p75:65} },
