  var html = '<div style="padding:0 0 4px;">';
  html += '<div style="display:grid;grid-template-columns:32px 1fr 100px 80px;gap:12px;padding:10px 28px;border-bottom:1px solid rgba(255,255,255,.05);">';
  html += '<span style="font-size:10px;color:rgba(242,240,235,.25);text-transform:uppercase;">#</span>';
